package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.nio.file.{Files, Path, Paths}
import java.nio.charset.StandardCharsets

@Singleton
class UserFilesController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  private val UploadsRoot: Path = Paths.get("uploads").toAbsolutePath.normalize()

  def serve(filename: String): Action[AnyContent] = Action {
    resolveSafePath(filename) match {
      case None =>
        NotFound
      case Some(path) =>
        if (!Files.exists(path) || !Files.isRegularFile(path)) {
          NotFound
        } else {
          val source = Source.fromFile(path.toFile)(StandardCharsets.UTF_8)
          try {
            Ok(source.mkString).as(contentTypeFor(path))
          } finally {
            source.close()
          }
        }
    }
  }

  private def resolveSafePath(filename: String): Option[Path] = {
    if (filename == null || filename.trim.isEmpty) return None

    val normalizedRel = Paths.get(filename).normalize()
    if (normalizedRel.isAbsolute) return None

    val resolved = UploadsRoot.resolve(normalizedRel).normalize()
    if (!resolved.startsWith(UploadsRoot)) None else Some(resolved)
  }

  private def contentTypeFor(path: Path): String = {
    val ct = try Option(Files.probeContentType(path)) catch { case _: Throwable => None }
    ct.getOrElse("application/octet-stream")
  }
}